import React, { useState } from 'react';
import { Star, ChevronLeft, ChevronRight } from 'lucide-react';
import { TESTIMONIALS } from '../constants';

const Testimonials: React.FC = () => {
  const [active, setActive] = useState(0);

  const next = () => setActive((prev) => (prev + 1) % TESTIMONIALS.length);
  const prev = () => setActive((prev) => (prev - 1 + TESTIMONIALS.length) % TESTIMONIALS.length);

  return (
    <section className="py-24 bg-blue-50/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold text-slate-900 mb-4">What Our Customers Say</h2>
          <p className="text-slate-600 max-w-2xl mx-auto">Providing stress-free relocations across the continent for over 30 years.</p>
        </div>

        <div className="relative">
          <div className="flex overflow-hidden">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full">
              {TESTIMONIALS.map((testimonial) => (
                <div key={testimonial.id} className="bg-white p-8 rounded-2xl shadow-sm flex flex-col items-center text-center">
                  <div className="flex space-x-1 mb-4">
                    {[...Array(testimonial.rating)].map((_, i) => (
                      <Star key={i} size={18} className="fill-yellow-400 text-yellow-400" />
                    ))}
                  </div>
                  <p className="italic text-slate-600 mb-8 leading-relaxed">
                    "{testimonial.text}"
                  </p>
                  <h4 className="font-bold text-slate-800 uppercase tracking-wide text-sm">{testimonial.name}</h4>
                  <p className="text-blue-600 text-xs font-semibold mt-1">Verified Customer</p>
                </div>
              ))}
            </div>
          </div>

          {/* Navigation Controls */}
          <div className="flex justify-center mt-12 space-x-4">
            <button onClick={prev} className="p-3 rounded-full bg-white border border-slate-200 text-slate-600 hover:bg-blue-600 hover:text-white transition-all">
              <ChevronLeft size={20} />
            </button>
            <div className="flex items-center space-x-2">
               {TESTIMONIALS.map((_, i) => (
                 <div key={i} className={`h-2 rounded-full transition-all ${i === active ? 'w-6 bg-blue-600' : 'w-2 bg-slate-300'}`}></div>
               ))}
            </div>
            <button onClick={next} className="p-3 rounded-full bg-white border border-slate-200 text-slate-600 hover:bg-blue-600 hover:text-white transition-all">
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Testimonials;

